#define MAX_PD (3.0e6)
#define PRECISION 0.001
#define SPEC_HEAT_SI 1.75e6
#define K_SI 100
#define FACTOR_CHIP 0.5

const float t_chip = 0.0005f;
const float chip_height = 0.016f;
const float chip_width = 0.016f;
const float amb_temp = 80.0f;

__kernel void hotspot(
    const int iter,
    const __global float* power,
    const __global float* temp,
    __global float* result,
    const int col,
    const int row,
    const int borderCols,
    const int borderRows,
    const float Cap,
    const float Rx,
    const float Ry,
    const float Rz,
    const float step)
{
    float Rx_1 = 1.f / Rx;
    float Ry_1 = 1.f / Ry;
    float Rz_1 = 1.f / Rz;
    float Cap_1 = step / Cap;

    int c = get_global_id(0);
    int r = get_global_id(1);

    if (c >= col || r >= row) return;

    int idx = r * col + c;

    float current_temp = temp[idx];

    for (int i = 0; i < iter; i++) {
        float delta;

        if (r == 0 && c == 0) {
            delta = Cap_1 * (power[idx] +
                (temp[idx + 1] - current_temp) * Rx_1 +
                (temp[idx + col] - current_temp) * Ry_1 +
                (amb_temp - current_temp) * Rz_1);
        }
        else if (r == 0 && c == col - 1) {
            delta = Cap_1 * (power[idx] +
                (temp[idx - 1] - current_temp) * Rx_1 +
                (temp[idx + col] - current_temp) * Ry_1 +
                (amb_temp - current_temp) * Rz_1);
        }
        else if (r == row - 1 && c == col - 1) {
            delta = Cap_1 * (power[idx] +
                (temp[idx - 1] - current_temp) * Rx_1 +
                (temp[idx - col] - current_temp) * Ry_1 +
                (amb_temp - current_temp) * Rz_1);
        }
        else if (r == row - 1 && c == 0) {
            delta = Cap_1 * (power[idx] +
                (temp[idx + 1] - current_temp) * Rx_1 +
                (temp[idx - col] - current_temp) * Ry_1 +
                (amb_temp - current_temp) * Rz_1);
        }
        else if (r == 0) {
            delta = Cap_1 * (power[idx] +
                (temp[idx + 1] + temp[idx - 1] - 2.0f * current_temp) * Rx_1 +
                (temp[idx + col] - current_temp) * Ry_1 +
                (amb_temp - current_temp) * Rz_1);
        }
        else if (c == col - 1) {
            delta = Cap_1 * (power[idx] +
                (temp[idx + col] + temp[idx - col] - 2.0f * current_temp) * Ry_1 +
                (temp[idx - 1] - current_temp) * Rx_1 +
                (amb_temp - current_temp) * Rz_1);
        }
        else if (r == row - 1) {
            delta = Cap_1 * (power[idx] +
                (temp[idx + 1] + temp[idx - 1] - 2.0f * current_temp) * Rx_1 +
                (temp[idx - col] - current_temp) * Ry_1 +
                (amb_temp - current_temp) * Rz_1);
        }
        else if (c == 0) {
            delta = Cap_1 * (power[idx] +
                (temp[idx + col] + temp[idx - col] - 2.0f * current_temp) * Ry_1 +
                (temp[idx + 1] - current_temp) * Rx_1 +
                (amb_temp - current_temp) * Rz_1);
        }
        else {
            delta = Cap_1 * (power[idx] +
                (temp[idx + col] + temp[idx - col] - 2.0f * current_temp) * Ry_1 +
                (temp[idx + 1] + temp[idx - 1] - 2.0f * current_temp) * Rx_1 +
                (amb_temp - current_temp) * Rz_1);
        }

        current_temp = current_temp + delta;
    }

    result[idx] = current_temp;
}
